// 1. Extract the raw output from the AI Agent node
let rawOutput = $input.first().json.output;

// Fallback in case model node nests it under 'message'
if (!rawOutput && $input.first().json.message) {
    rawOutput = $input.first().json.message.text || $input.first().json.message.content;
}

let targetText = '';

// 2. Dynamically determine the structure of the response
if (Array.isArray(rawOutput)) {
    // If it's an array (with thinking + text), find the block that is explicitly text
    const textBlock = rawOutput.find(block => block.type === 'text' || (block.text && !block.thinking));
    targetText = textBlock ? textBlock.text : '';
} else if (typeof rawOutput === 'string') {
    // If the response is already clean, use it directly
    targetText = rawOutput;
} else if (typeof rawOutput === 'object' && rawOutput !== null) {
    // If it's a single direct block object
    targetText = rawOutput.text || JSON.stringify(rawOutput);
}

// 3. Defensive clean-up: Strip Markdown fences if the LLM accidentally included them
targetText = targetText.replace(/```json/gi, '').replace(/```/gi, '').trim();

// 4. Parse the clean string into a structured JSON object for downstream nodes
try {
    const parsedData = JSON.parse(targetText);

    // Return the keys directly at the root so n8n can read them natively
    return parsedData; 
} catch (error) {
    // Critical failure fallback to prevent the whole workflow from stopping silently
    return {
        parsing_failed: true,
        error_message: error.message,
        raw_text_recovered: targetText
    };
}

// Ensure you use the correct proxy IP/URL from your GEMRAT setup
const targetUrl = 'https://10.0.27.228/'; 

try {
  const response = await this.helpers.request({
    method: 'GET',
    url: targetUrl,
    timeout: 3000, // Hard 3-second network limit. No locking up.
    validateStatus: function (status) {
      return true; // Force axios to NEVER throw an error for any status code (2xx, 4xx, 5xx)
    },
  });

  return {
    status: "executed",
    is_up: response.status >= 200 && response.status < 400,
    http_status_code: response.status,
    message: `Proxy/Server responded with HTTP status ${response.status}`
  };

} catch (error) {
  // Captures ECONNREFUSED, ETIMEDOUT, and host unreachable natively
  return {
    status: "executed",
    is_up: false,
    http_status_code: null,
    message: `CRITICAL NETWORK ERROR: The proxy or host at ${targetUrl} is completely down. System error: ${error.message}`
  };
}
